import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export class HeistTimerParser implements IMessageParser
{
private _roomId = 0;
private _gangId = 0;
private _remainingSeconds = 0;
private _totalSeconds = 0;

public flush(): boolean
{
this._roomId = 0;
this._gangId = 0;
this._remainingSeconds = 0;
this._totalSeconds = 0;
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean
{
if(!wrapper) return false;

// Must match HeistTimerComposer.java order:
// roomId, gangId, remainingSeconds, totalSeconds
this._roomId = wrapper.readInt();
this._gangId = wrapper.readInt();
this._remainingSeconds = wrapper.readInt();
this._totalSeconds = wrapper.readInt();

return true;
}

public get roomId(): number
{
return this._roomId;
}

public get gangId(): number
{
return this._gangId;
}

public get remainingSeconds(): number
{
return this._remainingSeconds;
}

public get totalSeconds(): number
{
return this._totalSeconds;
}
}